#pragma once

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cstdio>
#include <stdint.h>

// GEMM constants - optimized for A800
constexpr int GEMM_N = 128;
constexpr int GEMM_K = 2048;
constexpr int TILE_M = 16;
constexpr int TILE_N = 16;
constexpr int TILE_K = 64;
constexpr int BLOCK_THREADS = 256;

// Optimized kernel for A800
__global__ void gemm_kernel_optimized(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int M,
    int N,
    int K
);

// Host function declaration
void launch_gemm_kernel(
    const half* A,
    const half* B,
    half* C,
    int M,
    int N,
    int K,
    cudaStream_t stream = 0
);

// Error checking macro
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            fprintf(stderr, "CUDA error at %s:%d: %s\n", __FILE__, __LINE__, \
                    cudaGetErrorString(err)); \
            exit(EXIT_FAILURE); \
        } \
    } while(0)

#include "kernel.h"

// Shared memory tiles for A and B
// A_tile: [TILE_M][TILE_K] stores A[row, k]
// B_tile: [TILE_K][TILE_N] stores B[col, k]
__shared__ half A_tile[TILE_M][TILE_K];
__shared__ half B_tile[TILE_K][TILE_N];

__global__ void gemm_kernel_optimized(
    const half* __restrict__ A,
    const half* __restrict__ B,
    half* __restrict__ C,
    int M,
    int N,
    int K
) {
    // Thread indices within block
    int tx = threadIdx.x;  // 0 to TILE_N-1 (16)
    int ty = threadIdx.y;  // 0 to TILE_M-1 (16)
    int bx = blockIdx.x;
    int by = blockIdx.y;

    // Calculate global row and column indices for output C
    // row corresponds to M dimension
    // col corresponds to N dimension
    int row = by * TILE_M + ty;
    int col = bx * TILE_N + tx;

    // Accumulator in FP32 for better precision
    float acc = 0.0f;

    // Compute dot product over K dimension using tiles
    for (int t = 0; t < K / TILE_K; ++t) {
        int k_start = t * TILE_K;

        // Load A tile into shared memory
        // A is [M, K], so A[row, k]
        // Each thread loads TILE_K/TILE_N = 4 elements to cover the full K dimension
        for (int i = 0; i < TILE_K / TILE_N; ++i) {
            int k_idx = k_start + tx + i * TILE_N;
            if (row < M && k_idx < K) {
                A_tile[ty][tx + i * TILE_N] = A[row * K + k_idx];
            } else {
                A_tile[ty][tx + i * TILE_N] = __float2half(0.0f);
            }
        }

        // Load B tile into shared memory
        // B is [N, K], we compute A @ B.T
        // So we need B[col, k] for the dot product
        // Each thread loads TILE_K/TILE_M = 4 elements to cover the full K dimension
        for (int i = 0; i < TILE_K / TILE_M; ++i) {
            int k_idx = k_start + ty + i * TILE_M;
            if (col < N && k_idx < K) {
                B_tile[ty + i * TILE_M][tx] = B[col * K + k_idx];
            } else {
                B_tile[ty + i * TILE_M][tx] = __float2half(0.0f);
            }
        }

        __syncthreads();

        // Compute partial dot product for this tile
        // Thread (ty, tx) computes: sum_k A[row, k] * B[col, k]
        for (int k = 0; k < TILE_K; ++k) {
            float a_val = __half2float(A_tile[ty][k]);
            float b_val = __half2float(B_tile[k][tx]);
            acc += a_val * b_val;
        }

        __syncthreads();
    }

    // Write result to global memory
    if (row < M && col < N) {
        C[row * N + col] = __float2half(acc);
    }
}

void launch_gemm_kernel(
    const half* A,
    const half* B,
    half* C,
    int M,
    int N,
    int K,
    cudaStream_t stream
) {
    // Configuration for A800
    dim3 block(TILE_N, TILE_M);  // 16x16 = 256 threads per block
    dim3 grid((N + TILE_N - 1) / TILE_N, 
              (M + TILE_M - 1) / TILE_M);

    // Launch kernel
    gemm_kernel_optimized<<<grid, block, 0, stream>>>(
        A, B, C, M, N, K
    );

    // Check for launch errors
    CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include "kernel.h"
#include <stdexcept>
#include <iostream>

/**
 * Main run function that accepts PyTorch tensors
 * 
 * Args:
 *   A: torch::Tensor of shape [M, K] with dtype FP16
 *   B: torch::Tensor of shape [N, K] with dtype FP16
 *   C: torch::Tensor of shape [M, N] with dtype FP16 (optional, for in-place operation)
 * 
 * Returns:
 *   C: torch::Tensor of shape [M, N] with dtype FP16
 */
torch::Tensor run(const torch::Tensor& A, const torch::Tensor& B, const torch::Tensor& C = torch::Tensor()) {
    // Validate input tensors
    if (!A.is_cuda()) {
        throw std::runtime_error("Input tensor A must be on CUDA device");
    }
    if (!B.is_cuda()) {
        throw std::runtime_error("Input tensor B must be on CUDA device");
    }

    if (A.dtype() != torch::kHalf) {
        throw std::runtime_error("Input tensor A must be of dtype FP16");
    }
    if (B.dtype() != torch::kHalf) {
        throw std::runtime_error("Input tensor B must be of dtype FP16");
    }

    // Validate shapes
    if (A.dim() != 2) {
        throw std::runtime_error("Input tensor A must be 2D");
    }
    if (B.dim() != 2) {
        throw std::runtime_error("Input tensor B must be 2D");
    }

    int64_t M = A.size(0);
    int64_t K_A = A.size(1);
    int64_t N = B.size(0);
    int64_t K_B = B.size(1);

    if (K_A != K_B) {
        throw std::runtime_error(
            "Inner dimensions must match: A has K=" + 
            std::to_string(K_A) + ", B has K=" + std::to_string(K_B)
        );
    }

    // Validate fixed dimensions
    if (N != GEMM_N) {
        throw std::runtime_error(
            "N dimension must be " + std::to_string(GEMM_N) + 
            ", got " + std::to_string(N)
        );
    }

    if (K_A != GEMM_K) {
        throw std::runtime_error(
            "K dimension must be " + std::to_string(GEMM_K) + 
            ", got " + std::to_string(K_A)
        );
    }

    // Check M dimension fits in int
    if (M > INT_MAX) {
        throw std::runtime_error("M dimension too large for int");
    }
    int M_int = static_cast<int>(M);

    // Create or use provided output tensor
    torch::Tensor output;
    if (C.defined() && C.numel() > 0) {
        // Use provided output tensor for in-place operation
        if (C.dtype() != torch::kHalf) {
            throw std::runtime_error("Output tensor C must be of dtype FP16");
        }
        if (C.dim() != 2) {
            throw std::runtime_error("Output tensor C must be 2D");
        }
        if (C.size(0) != M || C.size(1) != N) {
            throw std::runtime_error(
                "Output tensor C must have shape [" + 
                std::to_string(M) + ", " + std::to_string(N) + 
                "], got [" + std::to_string(C.size(0)) + ", " + 
                std::to_string(C.size(1)) + "]"
            );
        }
        output = C;
    } else {
        // Create new output tensor
        output = torch::empty({M, N}, 
            torch::TensorOptions().dtype(torch::kHalf).device(torch::kCUDA));
    }

    // Get raw pointers - use at::Half type which is PyTorch's half type
    const at::Half* A_ptr = A.data_ptr<at::Half>();
    const at::Half* B_ptr = B.data_ptr<at::Half>();
    at::Half* C_ptr = output.data_ptr<at::Half>();

    // Cast to CUDA half type for kernel call
    const half* A_half = reinterpret_cast<const half*>(A_ptr);
    const half* B_half = reinterpret_cast<const half*>(B_ptr);
    half* C_half = reinterpret_cast<half*>(C_ptr);

    // Get current CUDA stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // Launch kernel
    launch_gemm_kernel(A_half, B_half, C_half, M_int, N, K_A, stream);

    // Check for errors
    CUDA_CHECK(cudaGetLastError());

    return output;
}

// PyBind11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "GEMM kernel for A800 GPU with fixed N=128, K=2048";

    m.def("run", &run, 
        "Execute GEMM operation with A[M, K] and B[N, K] to produce C[M, N]",
        py::arg("A"),
        py::arg("B"),
        py::arg("C") = torch::Tensor()
    );
}
